'use client'

import { useState, useEffect } from 'react'
import type { BlogAuthor, BlogPost } from '@growth-engine/types'
import { sdkFetch } from '../client'

interface UseAuthorsResult {
  authors: BlogAuthor[]
  loading: boolean
  error: string | null
}

export function useAuthors(): UseAuthorsResult {
  const [authors, setAuthors] = useState<BlogAuthor[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false

    async function load() {
      setLoading(true)
      const res = await sdkFetch<BlogAuthor[]>('/content?type=blog-authors')
      if (cancelled) return
      if (res.error) {
        setError(res.error)
      } else {
        setAuthors(res.data)
      }
      setLoading(false)
    }

    void load()
    return () => {
      cancelled = true
    }
  }, [])

  return { authors, loading, error }
}

export async function fetchAuthor(slug: string): Promise<BlogAuthor | null> {
  const params = new URLSearchParams({ type: 'blog-authors', slug })
  const res = await sdkFetch<BlogAuthor>(`/content?${params.toString()}`)
  return res.error ? null : res.data
}

interface FetchAuthorPostsOptions {
  locale?: string
  limit?: number
  offset?: number
}

export async function fetchAuthorPosts(
  authorSlug: string,
  options?: FetchAuthorPostsOptions,
): Promise<BlogPost[]> {
  const params = new URLSearchParams({ type: 'blog', authorSlug })
  if (options?.locale) params.set('locale', options.locale)
  if (options?.limit !== undefined) params.set('limit', String(options.limit))
  if (options?.offset !== undefined) params.set('offset', String(options.offset))
  const res = await sdkFetch<BlogPost[]>(`/content?${params.toString()}`)
  return res.error ? [] : res.data
}
