'use client'

import { useState, useEffect } from 'react'
import type { BusinessConfig } from '@growth-engine/types'
import { sdkFetch } from '../client'

interface UseBusinessConfigResult {
  config: BusinessConfig | null
  loading: boolean
  error: string | null
}

export function useBusinessConfig(): UseBusinessConfigResult {
  const [config, setConfig] = useState<BusinessConfig | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false

    async function load() {
      setLoading(true)
      const res = await sdkFetch<BusinessConfig>('/config')
      if (cancelled) return
      if (res.error) {
        setError(res.error)
      } else {
        setConfig(res.data)
      }
      setLoading(false)
    }

    void load()
    return () => {
      cancelled = true
    }
  }, [])

  return { config, loading, error }
}

export async function getHours(): Promise<Record<string, unknown> | null> {
  const res = await sdkFetch<BusinessConfig>('/config')
  return res.error ? null : res.data.hours
}

export async function getContactInfo(): Promise<Record<string, unknown> | null> {
  const res = await sdkFetch<BusinessConfig>('/config')
  return res.error ? null : res.data.contact
}
