import type { JobTriggerResponse } from '@growth-engine/types'
import { sdkFetch } from '../client'

export async function triggerSocialSync(
  platforms?: ('instagram' | 'linkedin' | 'facebook')[],
): Promise<JobTriggerResponse> {
  const res = await sdkFetch<JobTriggerResponse>('/jobs', {
    method: 'POST',
    body: JSON.stringify({ type: 'social.sync', payload: { platforms } }),
  })
  if (res.error) {
    throw new Error(res.error)
  }
  return res.data
}
