'use client'

import { useState, useEffect } from 'react'
import type { BlogPost, SocialPost } from '@growth-engine/types'
import { sdkFetch } from '../client'

type ContentType = 'blog' | 'social'

interface UseContentResult<T> {
  posts: T[]
  loading: boolean
  error: string | null
}

interface UseContentOptions {
  locale?: string
}

export function useContent(type: 'blog', options?: UseContentOptions): UseContentResult<BlogPost>
export function useContent(type: 'social', options?: UseContentOptions): UseContentResult<SocialPost>
export function useContent(type: ContentType, options?: UseContentOptions): UseContentResult<BlogPost | SocialPost> {
  const [posts, setPosts] = useState<(BlogPost | SocialPost)[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const locale = options?.locale

  useEffect(() => {
    let cancelled = false

    async function load() {
      setLoading(true)
      const params = new URLSearchParams({ type })
      if (locale) params.set('locale', locale)
      const res = await sdkFetch<(BlogPost | SocialPost)[]>(`/content?${params.toString()}`)
      if (cancelled) return
      if (res.error) {
        setError(res.error)
      } else {
        setPosts(res.data)
      }
      setLoading(false)
    }

    void load()
    return () => {
      cancelled = true
    }
  }, [type, locale])

  return { posts, loading, error }
}

export async function fetchBlog(slugOrUrlPath: string, locale?: string): Promise<BlogPost | null> {
  const params = new URLSearchParams({ type: 'blog', slug: slugOrUrlPath })
  if (locale) params.set('locale', locale)
  const res = await sdkFetch<BlogPost>(`/content?${params.toString()}`)
  return res.error ? null : res.data
}

/**
 * Build the canonical URL path for a blog post from its urlPath or slug.
 * Returns a path like "/blog/2026/03/my-post" if urlPath is set,
 * or "/blog/my-post" as fallback.
 */
export function getBlogUrl(post: Pick<BlogPost, 'slug' | 'urlPath'>): string {
  const path = post.urlPath ?? post.slug
  return `/blog/${path}`
}

export async function getSocialPosts(
  platform: 'instagram' | 'linkedin' | 'facebook',
): Promise<SocialPost[]> {
  const res = await sdkFetch<SocialPost[]>(
    `/content?type=social&platform=${encodeURIComponent(platform)}`,
  )
  return res.error ? [] : res.data
}
