import { sdkFetch } from '../client'

export interface PushLeadData {
	firstName: string
	lastName?: string
	email?: string
	phone?: string
	company?: string
}

export interface PushLeadResult {
	ok: boolean
	contactId?: string
	existing?: boolean
	error?: string
}

export async function pushLead(data: PushLeadData): Promise<PushLeadResult> {
	const res = await sdkFetch<PushLeadResult>('/crm?action=push-lead', {
		method: 'POST',
		body: JSON.stringify(data),
	})
	return res.error ? { ok: false, error: res.error } : res.data
}
